-- ============================================================
-- Migration 014 — Section 5 content (Locational Influence)
-- Bulk-loads M2-S5-C1 (Mortgage Lending) and M2-S5-C2
-- (Litigation Support), 10 scenarios per category, 20 total.
--
-- Difficulty distribution (per category):
--   #1, #2  · introductory
--   #3, #4  · basic
--   #5, #6  · intermediate
--   #7, #8  · advanced
--   #9, #10 · expert
--
-- After this migration:
--   - M2-S5-C1 (Mortgage Lending) has 10 of 10 scenarios loaded.
--   - M2-S5-C2 (Litigation Support) has 10 of 10 scenarios loaded.
--   - Section 5 is 2 of 6 categories complete.
--
-- No schema changes. The factor_analysis field type and the six
-- M2-S5 categories were created in Session 1 (migration 013).
-- Section-level defaults from Session 1:
--   classification_options = ['Positive','Negative','Neutral','Market-Dependent']
--   min_rationale_chars    = 20
-- These are repeated explicitly in each field_options_override
-- for self-describing scenario rows.
--
-- Idempotency: this migration runs once and is recorded in the
-- migration tracker by the migration runner.
-- ============================================================

BEGIN;

-- ============================================================
-- M2-S5-C1 — Mortgage Lending (10 scenarios)
-- ============================================================

-- ─────────────────────────────────────────────────────
-- Scenario 1: 214 Paddock Lane, Simpsonville — Cul-de-Sac with HOA Buffer (Saddlebrook)
-- Category M2-S5-C1 #1 · difficulty 'introductory'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 1,
  'introductory',
  '214 Paddock Lane, Simpsonville — Cul-de-Sac with HOA Buffer (Saddlebrook)',
  'You are appraising the property at 214 Paddock Lane, Simpsonville, SC 29681 for a conventional residential purchase loan. The subject is 4BR/2.5BA · 2,180 SF · 2019-built SFR · Saddlebrook Subdivision. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each present factor as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence, and write a brief market-supported rationale for each classification. Distractor factors that are not present at this location must be left unchecked. Every classification must be grounded in specific evidence from the location profile — this assignment evaluates evidence-based locational analysis, not pattern recognition or reflexive checklist behavior.'
FROM scenario_categories WHERE code = 'M2-S5-C1';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "214 Paddock Lane, Simpsonville, SC 29681", "subject_summary": "4BR/2.5BA · 2,180 SF · 2019-built SFR · Saddlebrook Subdivision"}, "location_profile": ["Saddlebrook is a conventional single-family subdivision developed 2015–2022 in Simpsonville, southern Greenville County, approximately 12 miles southeast of downtown Greenville. The neighborhood has approximately 280 homes on 0.18–0.35 acre lots. Internal streets loop and terminate in several cul-de-sacs. Homes are owner-occupied and well-maintained with no observable deferred maintenance.", "214 Paddock Lane sits at the end of a cul-de-sac, with a fan-shaped lot backing to a maintained HOA common area buffer strip separating the subdivision from a Publix-anchored retail center approximately 300 feet west. A mature 8-foot evergreen hedge eliminates rear visibility of the shopping center and no commercial noise is audible from the property. The subject is in the Simpsonville/Hillcrest school zone — a documented buyer preference driver — and FEMA Zone X is confirmed. The nearest arterial, Fairview Road, is approximately 0.4 miles away."], "factors": [{"id": "A", "label": "Cul-de-sac location"}, {"id": "B", "label": "Backing to HOA common area"}, {"id": "C", "label": "Proximity to retail/commercial use (screened)"}, {"id": "D", "label": "Desirable school district (Simpsonville/Hillcrest)"}, {"id": "E", "label": "FEMA Zone X (minimal flood hazard)"}, {"id": "F", "label": "Corner lot location"}, {"id": "G", "label": "Railroad proximity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Identification requires evidence, not habit. Neither a corner lot (F) nor railroad proximity (G) has any basis in the location profile. Every identified factor must have a specific, articulable basis in the described location — not a reflexive checklist.", "Teaching Point 2 — Neutral is not the same as absent. Retail proximity (C) must be identified as present even when classified Neutral. The physical buffer eliminates market impact, but the factor exists and must be acknowledged in the report. Omitting it is a reporting error; adjusting for it without evidence is an analytical error.", "Teaching Point 3 — Classification requires market support. Each Positive here is grounded in documented market behavior — buyers'' agent citations, lender recognition of Zone X, and established buyer preference for cul-de-sac locations. Classification without supporting evidence is opinion, not analysis."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "The subject is at the end of a cul-de-sac with minimal through-traffic. Cul-de-sac locations are consistently preferred by suburban buyers for reduced traffic and enhanced safety — a supported Positive."}, "B": {"present": true, "classification": "Positive", "rationale": "The subject backs to a maintained HOA buffer strip providing rear privacy and separation from commercial uses — a distinguishable positive relative to lots backing adjacent private properties."}, "C": {"present": true, "classification": "Neutral", "rationale": "The retail center is 300 feet away but the 8-foot HOA hedge eliminates visibility and no noise is audible. Physical mitigation renders this Neutral — but the factor must still be disclosed in the report."}, "D": {"present": true, "classification": "Positive", "rationale": "Buyers'' agents consistently cite the Simpsonville/Hillcrest zone as a market preference driver — a documented, market-supported Positive, not an assumption."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X status eliminates flood insurance requirements and confirms low natural hazard exposure — a positive condition recognized by both buyers and lenders."}, "F": {"present": false}, "G": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C1'
  AND s.order_index = 1;

