INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "318 Stonegate Drive, Taylors, SC 29687", "subject_summary": "3BR/2BA · 1,840 SF · 2004-built SFR · Stonegate Crossing"}, "location_profile": ["Stonegate Crossing is an established subdivision of approximately 190 homes developed 2000–2008 in Taylors, northeastern Greenville County, about 8 miles from downtown Greenville. Internal streets form a loop pattern with multiple through-connections; the subdivision has no cul-de-sacs. Homes are owner-occupied with some deferred exterior maintenance on older units.", "318 Stonegate Drive is a midblock through-street lot. The rear property line abuts a Duke Energy transmission easement approximately 60 feet wide with steel transmission towers visible from the rear yard and no privacy buffer. The subject is in the Taylors/Wade Hampton school zone, described as average-performing with no documented buyer preference behavior. FEMA Zone X is confirmed. The nearest commercial use is a strip center 0.8 miles south — no direct adjacency or visibility impact on the subject."], "factors": [{"id": "A", "label": "Transmission line easement along rear lot line"}, {"id": "B", "label": "Through-street location (no cul-de-sac)"}, {"id": "C", "label": "FEMA Zone X"}, {"id": "D", "label": "Average school district (no documented premium)"}, {"id": "E", "label": "Established neighborhood with mature landscaping"}, {"id": "F", "label": "Cul-de-sac location"}, {"id": "G", "label": "Proximity to retail/commercial use"}, {"id": "H", "label": "HOA common area backing"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Negative factors must be identified. Students who identify only positive factors are producing incomplete analysis. Both the transmission easement (A) and through-street location (B) are present and documented — both require identification and Negative classification.", "Teaching Point 2 — Neutral requires affirmative support. The school district is Neutral not by default, but because the profile provides specific evidence: average-performing, no documented buyer preference behavior. Students who default Positive for any school district without reading the market evidence are applying assumptions.", "Teaching Point 3 — Cul-de-sac distractor revisited. Factor F is deliberately placed in a location where it does not exist — the profile explicitly states the subdivision has no cul-de-sacs. Students who check F are applying a pattern from Scenario 1 rather than reading this location description."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "The 60-foot Duke Energy easement has towers clearly visible from the rear yard and no privacy buffer. Transmission easement adjacency is consistently associated with buyer resistance and downward price pressure in suburban residential markets."}, "B": {"present": true, "classification": "Negative", "rationale": "The subject is on a midblock through-street; the profile explicitly states the subdivision has no cul-de-sacs. Through-street exposure carries higher traffic volume that buyers typically discount relative to lower-traffic configurations."}, "C": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no flood insurance requirement. A positive locational characteristic recognized by buyers and lenders."}, "D": {"present": true, "classification": "Neutral", "rationale": "The zone is described as average-performing with no documented buyer preference behavior. Neutral — not Positive — is correct when the evidence does not support a directional premium."}, "E": {"present": true, "classification": "Positive", "rationale": "Full build-out 2000–2008 produces a stable, owner-occupied neighborhood with mature landscaping — positive relative to active construction zones or transitional areas."}, "F": {"present": false}, "G": {"present": false}, "H": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C1'
  AND s.order_index = 2;

