INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "742 Millbrook Way, Boiling Springs, SC 29316", "subject_summary": "4BR/2BA · 1,960 SF · 2012-built SFR · Millbrook Estates"}, "location_profile": ["Millbrook Estates is a residential subdivision of approximately 220 homes developed 2008–2015 in Boiling Springs, western Spartanburg County, about 6 miles southwest of downtown Spartanburg. Lots range from 0.20 to 0.28 acres with a mix of loop streets and cul-de-sacs.", "742 Millbrook Way occupies a corner lot at the intersection of Millbrook Way and Creekstone Court — approximately 0.31 acres with street exposure on two sides. A QuikTrip convenience store and gas station is approximately 200 feet from the subject, visible from the front yard and audible at peak hours due to traffic queuing at the fuel island. The subject is in the Boiling Springs school district, consistently top-rated in Spartanburg County and a documented family relocation search driver. FEMA Zone X is confirmed. SC-9 is accessible via Millbrook Road approximately 0.3 miles away, providing direct connectivity to Spartanburg and I-85."], "factors": [{"id": "A", "label": "Corner lot location"}, {"id": "B", "label": "Gas station / QuikTrip adjacency (~200 ft, visible and audible)"}, {"id": "C", "label": "Boiling Springs school district (top-rated in county)"}, {"id": "D", "label": "FEMA Zone X"}, {"id": "E", "label": "SC-9 regional road access (0.3 miles)"}, {"id": "F", "label": "Railroad proximity"}, {"id": "G", "label": "Power line easement"}, {"id": "H", "label": "HOA common area backing"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Market-Dependent requires a reason. Students who default to Positive (larger lot) or Negative (dual frontage) for the corner lot are making an unsupported directional call. Market-Dependent is the analytically honest answer when buyer response is genuinely split and paired sales evidence is needed to establish direction.", "Teaching Point 2 — Proximity externalities require specific evidence. The QuikTrip Negative is supported by three documented specifics: visibility, audibility, and peak-hour traffic. Rationales citing only ''gas station nearby'' without engaging these details do not demonstrate the evidence-based reasoning USPAP requires.", "Teaching Point 3 — Connectivity and noise are analytically distinct. SC-9 access (E) and the QuikTrip (B) both relate to the same road corridor but are separate factors with opposite directional effects. Conflating road access with commercial noise externality misses a fundamental analytical distinction."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Market-Dependent", "rationale": "Corner lots generate split buyer response — some value larger size and visibility; others are deterred by dual street exposure, reduced privacy, and additional maintenance. Market-Dependent is correct; direction requires paired sales evidence, not assumption."}, "B": {"present": true, "classification": "Negative", "rationale": "The QuikTrip is 200 feet away, visible from the front yard, and audible at peak hours. Commercial fuel operations at this proximity are consistently associated with noise, light, odor, and traffic that residential buyers discount."}, "C": {"present": true, "classification": "Positive", "rationale": "Top-rated in Spartanburg County with documented family search filter behavior — a market-supported Positive grounded in observed buyer behavior."}, "D": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no flood insurance requirement."}, "E": {"present": true, "classification": "Positive", "rationale": "Direct SC-9 access within 0.3 miles provides regional connectivity to Spartanburg and I-85 — a positive for buyers prioritizing commute access and regional connectivity."}, "F": {"present": false}, "G": {"present": false}, "H": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C1'
  AND s.order_index = 3;

