FROM scenario_categories WHERE code = 'M2-S5-C1';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "1205 Creekside Blvd, Simpsonville, SC 29680", "subject_summary": "3BR/2BA · 1,720 SF · 2007-built SFR · Creekside at Fairview"}, "location_profile": ["Creekside at Fairview is a residential subdivision of approximately 160 homes developed 2004–2010 in Simpsonville along a creek corridor. The subdivision has cul-de-sac fingers extending from a loop collector, with lots near the creek subject to varying FEMA flood designations. A stormwater management system was required as a condition of development.", "1205 Creekside Blvd is an interior lot whose rear property line falls within FEMA Zone AE — the 100-year floodplain — while the home footprint is in Zone X. The Zone AE/Zone X transition runs approximately 35 feet behind the rear building line. The rear yard experiences periodic standing water and has limited usability. Flood insurance is required by the lender due to Zone AE on any portion of the lot. The subject backs to a HOA-maintained stormwater detention pond — functional drainage infrastructure, not a natural water feature. The subject is in the Simpsonville/Hillcrest school zone. Fairview Road runs approximately 150 feet north with moderate daily traffic."], "factors": [{"id": "A", "label": "FEMA Zone AE designation (partial lot — rear portion)"}, {"id": "B", "label": "Stormwater detention pond backing"}, {"id": "C", "label": "Desirable school district (Simpsonville/Hillcrest)"}, {"id": "D", "label": "Collector road proximity (Fairview Road, ~150 ft)"}, {"id": "E", "label": "Cul-de-sac location"}, {"id": "F", "label": "Natural lake / scenic water amenity"}, {"id": "G", "label": "Mountain or scenic view"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Zone AE on any portion of the lot triggers flood insurance. Students who classify Zone AE as Neutral because the house footprint is in Zone X are misapplying FEMA rules. Lender requirements attach to the lot designation, not just the structure footprint — a critical lending knowledge point with direct impact on buyer financing costs.", "Teaching Point 2 — Infrastructure vs. amenity. The stormwater pond is drainage infrastructure, not a water amenity. Students who classify it Positive based on open space or water view are conflating two materially different attributes. Market-Dependent is correct because buyer response genuinely varies.", "Teaching Point 3 — Natural lake distractor (F). The profile explicitly describes a stormwater detention pond — not a lake. Students who check Factor F are re-identifying the same feature under a more favorable label, which is not analytically supportable."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "Zone AE on any portion of the lot triggers mandatory flood insurance regardless of where the structure sits. Rear yard standing water and limited usability compound the impact — a clear Negative affecting financing cost and property utility."}, "B": {"present": true, "classification": "Market-Dependent", "rationale": "The pond is drainage infrastructure, not a natural lake. Some buyers accept it neutrally; others view it as unattractive. Market-Dependent is appropriate — direction requires paired sales evidence, not assumption."}, "C": {"present": true, "classification": "Positive", "rationale": "Consistent with prior scenarios, the Simpsonville/Hillcrest zone is a documented buyer preference driver in this submarket."}, "D": {"present": true, "classification": "Negative", "rationale": "Fairview Road at approximately 150 feet introduces traffic noise and activity that buyers typically discount, despite some internal buffering from the subdivision entrance layout."}, "E": {"present": false}, "F": {"present": false}, "G": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C1'
  AND s.order_index = 4;

