INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "4417 Ashford Park Drive, Greenville, SC 29607", "subject_summary": "4BR/3BA · 2,340 SF · 2016-built SFR · Ashford Park"}, "location_profile": ["Ashford Park is an upscale subdivision off Woodruff Road in southeastern Greenville, approximately 5 miles from downtown. Developed 2013–2019, it contains approximately 310 homes on lots from 0.18 to 0.40 acres. HOA dues are $185/month, governing exterior standards, architectural modifications, and short-term rental activity within the community.", "4417 Ashford Park Drive backs directly to the Swamp Rabbit Trail — a 22-mile multiuse greenway widely cited as one of Greenville County''s premier residential amenities — with deeded trail access from this lot. Woodruff Road, a primary commercial arterial, is approximately 0.35 miles away and audible from the front of the home at peak hours. The subject is in the above-average Mauldin school zone with positive documented buyer reception. FEMA Zone X is confirmed. Buyers'' agents report split responses to the Woodruff Road corridor: some cite retail and dining access as a convenience positive; others discount the location for traffic and commercial character."], "factors": [{"id": "A", "label": "Backing to Swamp Rabbit Trail (deeded access)"}, {"id": "B", "label": "HOA with $185/month dues and use restrictions"}, {"id": "C", "label": "Woodruff Road traffic noise (audible, 0.35 miles)"}, {"id": "D", "label": "Mauldin school district (above average)"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "Woodruff Road retail/dining/employment access"}, {"id": "G", "label": "Railroad proximity"}, {"id": "H", "label": "Power line easement"}, {"id": "I", "label": "Corner lot"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Same source, two distinct factors. Factors C and F both derive from Woodruff Road but are analytically separate: C addresses noise externality (Negative) while F addresses convenience access (Market-Dependent). The market prices these dimensions independently — collapsing them into one factor loses a distinction that matters for adjustment analysis.", "Teaching Point 2 — HOA as Market-Dependent. At $185/month, HOA dues are a material carrying cost. The STR restriction adds complexity — buyers with STR intentions may view it as Negative; owner-occupants may view it as protective. Students who default Positive because ''HOA means maintained neighborhood'' are applying an assumption, not analyzing the specific structure.", "Teaching Point 3 — Swamp Rabbit Trail is documented, not assumed. The trail is Positive — not Market-Dependent — because the profile provides market evidence establishing direction. Students who classify it Market-Dependent are not distinguishing between factors where evidence establishes direction and those where it genuinely does not."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "The profile documents the trail as one of the county''s premier residential amenities with consistent buyer preference. Deeded access supports a Positive — not Market-Dependent — because the profile establishes market direction."}, "B": {"present": true, "classification": "Market-Dependent", "rationale": "HOA dues at $185/month are meaningful carrying cost. Some buyers value community standards and the STR restriction; others are deterred by cost and constraints. Market-Dependent requires paired sales to establish net direction."}, "C": {"present": true, "classification": "Negative", "rationale": "A high-volume commercial arterial audible from the front of the home at 0.35 miles is consistently Negative — the adverse buyer preference impact is not buyer-dependent."}, "D": {"present": true, "classification": "Positive", "rationale": "Above-average rating with documented positive buyer reception in this submarket — a market-supported Positive classification."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no flood insurance required."}, "F": {"present": true, "classification": "Market-Dependent", "rationale": "The profile documents split buyer response to corridor access — convenience positive for some, discounted for traffic by others. Market-Dependent is appropriate and analytically distinct from Factor C, which addresses noise externality from the same road."}, "G": {"present": false}, "H": {"present": false}, "I": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C1'
  AND s.order_index = 5;

