  f.id,
  '',
  '{"subject": {"address_summary": "819 Laurel Ridge Lane, Spartanburg, SC 29301", "subject_summary": "4BR/2.5BA · 2,100 SF · 2010-built SFR · Laurel Ridge"}, "location_profile": ["Laurel Ridge is a residential subdivision of approximately 175 homes in northwestern Spartanburg, developed 2006–2012, located approximately 3 miles from Spartanburg Regional Medical Center and 4 miles from downtown. The neighborhood has loop streets with several cul-de-sac fingers and an HOA maintaining a common area greenspace and walking path near the subdivision entrance.", "819 Laurel Ridge Lane is an interior lot on a low-traffic loop street backing to the HOA greenspace and walking path — a maintained open area of approximately 0.8 acres. Reidville Road, a designated arterial with significant freight and commuter traffic, runs approximately 0.4 miles north of the subject — confirmed not audible or visible from the property. A school district redistribution by Spartanburg SD6 took effect this year, reassigning the subject from Dorman High School — the district''s top-rated school — to a newer school with a shorter performance record. Buyers'' agents confirm prospective buyers seeking Dorman attendance have shifted their search areas. FEMA Zone X confirmed. Spartanburg Regional''s proximity contributes to stable employment-driven demand."], "factors": [{"id": "A", "label": "School attendance zone reassignment (away from Dorman zone)"}, {"id": "B", "label": "Spartanburg Regional Medical Center proximity (employment)"}, {"id": "C", "label": "HOA greenspace / walking path backing"}, {"id": "D", "label": "Reidville Road arterial proximity (0.4 miles — not audible)"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "Cul-de-sac location"}, {"id": "G", "label": "Power line easement"}, {"id": "H", "label": "Industrial use adjacency"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — School district changes are effective-date analysis. The reassignment is Negative — not Market-Dependent — because the profile provides documented market evidence: buyer search shifts are agent-confirmed. Locational analysis must reflect conditions at the effective date, not historical district assignments.", "Teaching Point 2 — Distance matters for arterial classifications. Reidville Road would be Negative at close proximity, but 0.4 miles with confirmed absence of audibility and visibility makes Neutral correct. Classifying any arterial as Negative regardless of distance is applying a rule, not performing analysis.", "Teaching Point 3 — Market-Dependent for employment generators. The Medical Center is Market-Dependent because employment demand and expansion/traffic concerns pull in opposite directions. Students who simplify this to Positive are overstating certainty of direction without paired sales support from this submarket."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "Reassignment from the district''s top-rated school to a lower-track alternative, with agent-confirmed buyer search shifts, supports Negative — not Market-Dependent. Direction is established by evidence, not merely possible."}, "B": {"present": true, "classification": "Market-Dependent", "rationale": "Hospital proximity drives stable employment demand (positive) but raises traffic and expansion concerns for some buyers (negative). Market-Dependent is appropriate; direction requires paired sales from this specific submarket."}, "C": {"present": true, "classification": "Positive", "rationale": "Backing to a maintained HOA open area with a walking path provides rear yard privacy and recreational access — a consistent positive locational attribute."}, "D": {"present": true, "classification": "Neutral", "rationale": "Reidville Road is an arterial but is 0.4 miles away, confirmed not audible or visible from the property. Distance attenuates negative impact to the point of no detectable market effect — Neutral, not Negative."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed."}, "F": {"present": false}, "G": {"present": false}, "H": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C1'
  AND s.order_index = 6;

