INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "2234 Ridge View Terrace, Landrum, SC 29356", "subject_summary": "3BR/2BA · 1,680 SF · 2001-built SFR · Blue Ridge Estates"}, "location_profile": ["Blue Ridge Estates is a subdivision of approximately 85 homes developed 1998–2005 in Landrum, along the Blue Ridge escarpment in northern Spartanburg County — approximately 30 miles from Spartanburg and 28 miles from Greenville. The area is semi-rural with mountain and pastoral views; most residents commute regionally. Commercial services are limited within the immediate area.", "2234 Ridge View Terrace occupies an elevated lot approximately 60 feet above the valley floor. The elevation provides unobstructed Blue Ridge mountain views prominently marketed in the original subdivision. The same elevated position exposes the lot to SC-14, a two-lane state highway at the base of the ridge — traffic noise is continuously audible, with freight traffic audible at night. The property is served by private well and septic; municipal utilities are unavailable at this location. The nearest grocery is approximately 12 miles away. Landrum School District is a small rural district with limited extracurricular programming relative to county alternatives. FEMA Zone X is confirmed. No HOA exists."], "factors": [{"id": "A", "label": "Blue Ridge mountain views (unobstructed, elevated lot)"}, {"id": "B", "label": "SC-14 highway noise (continuous, including nighttime freight)"}, {"id": "C", "label": "Private well and septic (no municipal utilities)"}, {"id": "D", "label": "Remote location / limited service access (12-mile grocery)"}, {"id": "E", "label": "Small rural school district (limited programming)"}, {"id": "F", "label": "FEMA Zone X"}, {"id": "G", "label": "HOA common area"}, {"id": "H", "label": "Industrial use adjacency"}, {"id": "I", "label": "FEMA Zone AE (flood hazard)"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Conflicting factors from the same source. Factors A (view) and B (highway noise) both result from the same elevated lot position but are analytically independent — both must be identified and classified. The view does not cancel the noise; the noise does not negate the view. Students who identify only one are providing incomplete locational analysis.", "Teaching Point 2 — Multiple negatives can coexist. This scenario has three Negative factors (B, D, E) plus one Market-Dependent (C). Students who stop after identifying the most prominent negative are conflating identification with reconciliation. Identification and classification come first; weighting and reconciliation come later.", "Teaching Point 3 — Rural utilities as Market-Dependent, not Negative. Private well and septic is not automatically Negative in rural markets where it is the norm. Market-Dependent is the honest call: primary buyers may resist; lifestyle buyers accept it. The appraiser must determine which buyer pool dominates this specific segment."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "The elevated lot provides unobstructed mountain views prominently marketed in the original subdivision. Mountain views carry documented premiums in the Blue Ridge submarket — a supported Positive classification."}, "B": {"present": true, "classification": "Negative", "rationale": "The same elevation that creates the view also exposes the lot to continuous SC-14 traffic, including nighttime freight. Audible, continuous highway noise is a documented Negative externality regardless of the coexisting positive view attribute."}, "C": {"present": true, "classification": "Market-Dependent", "rationale": "Buyer acceptance of private utilities varies: primary residential buyers often require municipal infrastructure; rural lifestyle buyers accept well/septic as characteristic. Market-Dependent requires paired sales from comparable rural utility configurations."}, "D": {"present": true, "classification": "Negative", "rationale": "A 12-mile grocery distance is a material service constraint for primary residential buyers — a documented Negative for buyers evaluating daily convenience in a non-resort market context."}, "E": {"present": true, "classification": "Negative", "rationale": "Limited extracurricular programming relative to county alternatives is a documented Negative for family buyers comparing suburban and rural school options."}, "F": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no flood insurance required."}, "G": {"present": false}, "H": {"present": false}, "I": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C1'
  AND s.order_index = 7;

