INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "1847 Augusta Road, Greenville, SC 29605", "subject_summary": "3BR/2BA · 1,540 SF · 1998-built (renovated 2019) · Augusta Road Corridor / No HOA"}, "location_profile": ["The subject is a renovated single-family residence on Augusta Road in Greenville, approximately 1.5 miles southwest of downtown. The Augusta Road corridor blends renovated historic homes with professional offices, independent restaurants, and service businesses. Significant reinvestment has occurred since 2015, documented in permit records throughout the corridor.", "1847 Augusta Road sits on a 0.14-acre lot with direct Augusta Road frontage. Augusta Road is a four-lane urban arterial — posted 35 mph with estimated daily traffic of 18,000–22,000 vehicles. The front setback is approximately 22 feet from the road edge. The immediately adjacent property to the south is a vacant commercial building with boarded windows, visible overgrowth, and approximately 4 years of inactivity per county records. The location offers walkable access within 0.5 miles to restaurants, a coffee shop, a fitness studio, and the Augusta Road retail district. Prisma Health''s downtown campus is 1.8 miles away; buyers'' agents identify an active healthcare worker buyer pool at this price range. Standard Greenville County school zone — no documented premium. FEMA Zone X confirmed. No HOA."], "factors": [{"id": "A", "label": "Augusta Road arterial frontage (22-ft setback, 18K–22K vehicles/day)"}, {"id": "B", "label": "Adjacent vacant/blighted commercial building (immediately south)"}, {"id": "C", "label": "Urban walkability / amenity access (within 0.5 miles)"}, {"id": "D", "label": "Medical employment proximity (Prisma Health, medical offices)"}, {"id": "E", "label": "Mixed residential/commercial corridor character"}, {"id": "F", "label": "FEMA Zone X"}, {"id": "G", "label": "HOA common area / amenity"}, {"id": "H", "label": "Premium school district"}, {"id": "I", "label": "Railroad proximity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Positives and negatives coexist without canceling. This scenario has three positives (C, D, F), two negatives (A, B), and one Market-Dependent (E). Students must identify all present factors without allowing positives to offset negatives during identification. Reconciliation is a separate task performed after all factors are correctly classified.", "Teaching Point 2 — Adjacent blight as an immediate externality. Factor B is the most proximate negative — no separation, no buffer, no mitigation. Students who overlook it are missing the externality most likely to require a downward adjustment in comparable selection, since comps without adjacent blight would need to be adjusted to match the subject.", "Teaching Point 3 — Corridor character is its own factor. Factor E (mixed-use character) is analytically distinct from walkability (C) and arterial noise (A). Some buyers choose this location for its mixed character; others eliminate it for the same reason — that split is what makes it Market-Dependent."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "Direct frontage on a 4-lane arterial at a 22-foot setback is consistently Negative for residential use — noise, air quality, and loss of privacy are documented buyer concerns at this exposure level."}, "B": {"present": true, "classification": "Negative", "rationale": "The immediately adjacent vacant building with boarded windows and overgrowth is a classic proximity externality. Adjacent blight at zero separation is a documented Negative affecting curb appeal, buyer perception, and comparable selection."}, "C": {"present": true, "classification": "Positive", "rationale": "Walkable access to food, fitness, and retail within 0.5 miles is a documented Positive in urban infill markets — particularly for the Augusta Road lifestyle buyer who actively seeks corridor proximity."}, "D": {"present": true, "classification": "Positive", "rationale": "Proximity to Greenville''s primary medical employment center with an agent-confirmed active healthcare worker buyer pool supports a Positive classification."}, "E": {"present": true, "classification": "Market-Dependent", "rationale": "Buyer response to living on a mixed-use corridor is genuinely split — some seek it; others exclude it. Market-Dependent is correct and analytically distinct from both walkability (C) and arterial noise (A)."}, "F": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed."}, "G": {"present": false}, "H": {"present": false}, "I": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C1'
  AND s.order_index = 8;

