INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "412 Pendleton Street, Greenville, SC 29601", "subject_summary": "3BR/2BA · 1,420 SF · 1935-built (renovated 2021) · West End / No HOA"}, "location_profile": ["The subject is a renovated bungalow in Greenville''s West End neighborhood, approximately 0.7 miles from downtown. The West End has experienced significant land use change over the past decade — former industrial properties along Pendleton Street have been redeveloped into mixed-use, residential, and office uses. The Swamp Rabbit Trail is within 0.3 miles; Falls Park on the Reedy is approximately 0.9 miles east.", "The subject falls within a Greenville City historic overlay district restricting exterior modifications and requiring design review. Property owners report split views: some value the overlay as protecting character; others find it burdensome. The City has approved a mixed-use corridor plan for Pendleton Street with first-phase construction projected within 18 months. Several adjacent lots have received demolition permits and multi-family/commercial redevelopment approvals in the past 36 months — associated in permit records with increased price volatility for residential properties in the immediate area. Short-term rental activity is active in the West End, but the City''s STR ordinance is under review with proposed amendments that may restrict STR licensing in residential zones. FEMA Zone X confirmed. Standard school zone — no documented premium."], "factors": [{"id": "A", "label": "Neighborhood in transition / changing land use pattern"}, {"id": "B", "label": "Historic overlay district restrictions"}, {"id": "C", "label": "Planned mixed-use development corridor (18-month timeline)"}, {"id": "D", "label": "STR zoning uncertainty (ordinance under active review)"}, {"id": "E", "label": "Urban proximity / Swamp Rabbit Trail and Falls Park access"}, {"id": "F", "label": "FEMA Zone X"}, {"id": "G", "label": "Residential price volatility from surrounding land use change"}, {"id": "H", "label": "Railroad proximity"}, {"id": "I", "label": "Premium school district"}, {"id": "J", "label": "HOA use restrictions"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Language discipline in transitional market analysis. Factor A classification must rely entirely on objective, market-supported evidence: permit records, price trends, agent-confirmed demand shifts. Any language referencing who is moving into or out of the neighborhood or demographic characteristics of residents is impermissible under Fair Housing and USPAP. The analytical task is identical to any other locational factor.", "Teaching Point 2 — Market-Dependent vs. Negative. Factors A, B, and C are Market-Dependent because buyer response is genuinely split and direction is indeterminate without further evidence. Factors D and G are Negative because direction is determinable — regulatory uncertainty trending toward restriction and price volatility are adverse regardless of individual buyer preference.", "Teaching Point 3 — Multiple Market-Dependent classifications are analytically legitimate. Urban infill profiles genuinely produce multiple factors where buyer response is split. Students who force directional classifications to avoid multiple Market-Dependent answers are introducing false precision. If the evidence produces three Market-Dependent factors, that is the correct answer."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Market-Dependent", "rationale": "Permit-documented land use change creates split buyer response: investors may view it positively for appreciation potential; stability-seeking buyers may view it negatively. Market-Dependent is appropriate — and all supporting language must reference objective market evidence (permits, price trends), not demographic characteristics of residents."}, "B": {"present": true, "classification": "Market-Dependent", "rationale": "The profile documents split owner perception — protective to some, burdensome to others. Market-Dependent is correct; paired sales must determine whether the overlay commands a preservation premium or imposes a restriction discount in this specific submarket."}, "C": {"present": true, "classification": "Market-Dependent", "rationale": "Approved corridor development introduces future density and amenity potential (positive to some) alongside construction disruption and character change (negative to others). Market-Dependent is appropriate for planned-but-not-yet-built development with uncertain net effect."}, "D": {"present": true, "classification": "Negative", "rationale": "Active regulatory review trending toward STR restriction represents potential loss of a use right. Unlike Market-Dependent factors, direction here is determinable — regulatory uncertainty skewing toward restriction is Negative for buyers who factored STR income into their purchase decision."}, "E": {"present": true, "classification": "Positive", "rationale": "Trail access within 0.3 miles and Falls Park within 0.9 miles, combined with downtown proximity, are documented positive amenities in Greenville''s urban residential market."}, "F": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed."}, "G": {"present": true, "classification": "Negative", "rationale": "Price volatility — separate from the direction of change — is a Negative locational indicator. Volatile comps reduce appraisal reliability and signal market instability that risk-averse buyers and lenders discount."}, "H": {"present": false}, "I": {"present": false}, "J": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C1'
  AND s.order_index = 9;

