  '',
  '{"subject": {"address_summary": "3318 Aviation Parkway, Greer, SC 29651", "subject_summary": "3BR/2BA · 1,780 SF · 2008-built SFR · Aviation Corridor / No HOA"}, "location_profile": ["The subject is in a small residential subdivision along Aviation Parkway in Greer, approximately 2 miles from Greenville-Spartanburg International Airport (GSP) and 4 miles from BMW Manufacturing''s main campus on SC-101. The 65-home subdivision was developed 2005–2010 on land formerly in an industrial corridor. Aviation Parkway is predominantly lined with warehouse, light industrial, and distribution facilities.", "The subject lot falls within the FAA Part 150 Airport Noise Compatibility Study noise contour at a Day-Night Average Sound Level (DNL) of 65 dB — the federal threshold at which residential use is considered marginally compatible. This designation triggers disclosure requirements for residential transactions and is reviewed under VA and FHA appraisal guidelines. BMW Manufacturing is the Upstate''s largest employer with over 11,000 direct employees; buyers'' agents consistently identify BMW employment proximity as a positive market driver, particularly for international workforce relocations. I-85 is accessible via SC-101 within 3 miles. The Greenville County school zone here is rated average — no documented premium. FEMA Zone X confirmed."], "factors": [{"id": "A", "label": "FAA Part 150 airport noise contour (DNL 65 dB)"}, {"id": "B", "label": "BMW Manufacturing proximity (major employer, ~4 miles)"}, {"id": "C", "label": "Predominantly industrial/warehouse surrounding land use"}, {"id": "D", "label": "I-85 / SC-101 regional connectivity (~3 miles)"}, {"id": "E", "label": "Average school district (no documented premium or discount)"}, {"id": "F", "label": "FEMA Zone X"}, {"id": "G", "label": "FAA disclosure obligation (triggered by noise contour)"}, {"id": "H", "label": "Mountain or scenic views"}, {"id": "I", "label": "HOA common area / amenity"}, {"id": "J", "label": "Historic overlay restrictions"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — FAA Part 150 and residential compatibility. The DNL 65 dB threshold is the federal standard for marginal residential compatibility, triggering specific requirements under VA and FHA guidelines. Regulatory designations create locational impacts beyond the physical effect — they alter disclosure requirements, lender review obligations, and buyer pool depth.", "Teaching Point 2 — Noise vs. disclosure as distinct factors. Factors A and G are both Negative but for different reasons: A addresses physical noise impact on livability; G addresses the regulatory and transactional consequences of the designation. Some buyers tolerate noise; few accept undisclosed mandatory disclosure obligations. These are separate market impacts.", "Teaching Point 3 — Industrial corridor as a market-area constraint. Factor C operates at the market area level — the residential use is the outlier in its land use context. This affects comparable selection, value stability, and long-term marketability. Expert-level analysis recognizes land use context as a locational factor independent of specific adjacent nuisances."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "The DNL 65 dB contour is the federal threshold for marginal residential compatibility and triggers mandatory disclosure requirements, with specific review under VA and FHA guidelines. Airport noise at this level is a Negative affecting marketability and buyer pool depth."}, "B": {"present": true, "classification": "Positive", "rationale": "BMW is the Upstate''s largest employer; agents confirm employment proximity as a documented positive market driver, particularly for the active international workforce relocation segment in the Greer/Duncan submarket."}, "C": {"present": true, "classification": "Negative", "rationale": "The subject subdivision is a residential island in an industrial corridor. Surrounding industrial land use is a Negative — it limits residential character, creates atypical traffic patterns, and reduces the buyer pool relative to conventionally residential settings."}, "D": {"present": true, "classification": "Positive", "rationale": "Interstate access within 3 miles via SC-101 is a Positive in a corridor defined by BMW and logistics employment, where commute connectivity is a documented buyer priority."}, "E": {"present": true, "classification": "Neutral", "rationale": "Average district performance with no documented buyer premium or discount supports a Neutral classification — consistent with the treatment of average-performing districts in prior scenarios."}, "F": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed."}, "G": {"present": true, "classification": "Negative", "rationale": "The disclosure obligation triggered by the noise contour is analytically distinct from the noise itself — it introduces transaction-level friction, may deter buyers upon disclosure, and signals a regulatory constraint on marketability. Negative and distinct from Factor A."}, "H": {"present": false}, "I": {"present": false}, "J": {"present": false}}}'::jsonb
FROM scenarios s
