INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "412 Lakeside Drive, Duncan, SC 29334", "subject_summary": "3BR/2BA · 1,760 SF · 2005-built SFR · Lakeside Commons", "context_label": "Litigation Context", "context_text": "Retained by plaintiff''s attorney. Claim: conversion of adjacent residential property to a commercial truck repair operation has caused measurable diminution in value."}, "location_profile": ["Lakeside Commons is a residential subdivision of approximately 140 homes developed 2001–2008 in Duncan, Spartanburg County, approximately 10 miles southwest of downtown Spartanburg. The neighborhood is bordered to the west by Lake Bowen, with deeded community water access for subdivision residents. Lots average 0.25 acres and streets are loop-configured with cul-de-sac fingers throughout.", "412 Lakeside Drive is a cul-de-sac lot with deeded HOA access to the community boat ramp and lakefront picnic area. Directly across the street, a formerly residential property has been converted to a commercial truck repair operation — diesel trucks queue on the street during business hours and mechanical noise is audible throughout the day. The subject is in the Boiling Springs school attendance zone, rated among the top districts in Spartanburg County. FEMA Zone X is confirmed."], "factors": [{"id": "A", "label": "Deeded community lake access (Lake Bowen)"}, {"id": "B", "label": "Across-street commercial truck repair operation"}, {"id": "C", "label": "Boiling Springs school district (top-rated)"}, {"id": "D", "label": "FEMA Zone X"}, {"id": "E", "label": "Cul-de-sac location"}, {"id": "F", "label": "HOA common area backing"}, {"id": "G", "label": "Power line / transmission easement"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Identify all factors, not just the dispute. In litigation support, appraisers sometimes over-focus on the disputed factor (B) and fail to identify all other locational influences. Complete analysis requires identifying every present factor — positive and negative — regardless of which factor is the subject of the claim.", "Teaching Point 2 — Classification is not advocacy. Whether retained by plaintiff or defendant, the correct classification for Factor B is Negative — it is not Market-Dependent simply because the magnitude is disputed. The appraiser''s role is to classify accurately based on market evidence, not to support a predetermined conclusion for the retaining party.", "Teaching Point 3 — Distractor discipline under litigation pressure. HOA common area backing (F) and power line easement (G) are not present in this scenario. In litigation contexts, appraisers face pressure to identify factors that support their client''s position. Students who check these distractors may be influenced by the legal context rather than the location evidence."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Positive", "rationale": "The lot includes deeded HOA community access to Lake Bowen — a documented positive amenity in this submarket where lake access drives consistent buyer preference."}, "B": {"present": true, "classification": "Negative", "rationale": "A commercial truck repair operation directly across a residential street — with queuing diesel trucks and audible mechanical noise — is a documented Negative for residential use. This is the subject of the diminution claim."}, "C": {"present": true, "classification": "Positive", "rationale": "Top-rated in Spartanburg County with documented buyer search filter behavior — a market-supported Positive classification."}, "D": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no flood insurance requirement."}, "E": {"present": true, "classification": "Positive", "rationale": "Cul-de-sac terminus with minimal through-traffic — a consistently preferred configuration in suburban residential markets."}, "F": {"present": false}, "G": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
