SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "3847 Chesnee Highway, Cowpens, SC 29330", "subject_summary": "3BR/2BA · 1,450 SF · 1998-built SFR · Rural Spartanburg County · 1.3 acres", "context_label": "Litigation Context", "context_text": "Retained by plaintiff''s attorney. Claim: a commercial hog farm that began operations approximately 2 years ago approximately 0.6 miles from the subject has caused measurable and ongoing diminution due to wind-dependent odor and agricultural industrial activity."}, "location_profile": ["The subject is a single-family residence on a 1.3-acre lot along Chesnee Highway in rural northern Spartanburg County, approximately 18 miles north of downtown Spartanburg and 8 miles from Gaffney. The area is characterized by agricultural and rural residential land uses with low density. The subject is served by private well and septic — municipal utilities are not available at this location. The nearest grocery is approximately 11 miles away.", "The subject is in the Cherokee County school district — a small rural district with limited extracurricular programming relative to Spartanburg County alternatives. FEMA Zone X is confirmed. A commercial hog farm began operations approximately 0.6 miles southeast of the subject 2 years ago. Odor impact varies with wind direction and is most pronounced during warm weather. Documented odor complaints from neighboring property owners have been filed with the county. No HOA exists. The agricultural and rural residential character of this market is the defining context for buyer expectations in this area."], "factors": [{"id": "A", "label": "Commercial hog farm odor (0.6 miles, wind-dependent)"}, {"id": "B", "label": "Rural/agricultural market area character"}, {"id": "C", "label": "Private well and septic (no municipal utilities)"}, {"id": "D", "label": "Limited service access (11-mile grocery)"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "Small rural school district (limited programming)"}, {"id": "G", "label": "HOA restrictions"}, {"id": "H", "label": "Industrial corridor / warehouse land use"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Distinguish the claim factor from the pre-existing market context. Factor A (hog farm odor) is the subject of the litigation. The remaining factors — B, C, D, F — describe the pre-existing locational context. Jurors and judges expect the appraiser to clearly distinguish between what existed before the nuisance and what the nuisance added to an already-constrained locational profile.", "Teaching Point 2 — Multiple negatives in rural markets. Students who see a rural scenario and assume a simple positive profile miss the analytical complexity: Factors A, D, and F are all Negative. Omitting pre-existing negatives to overstate the damage claim is as problematic as omitting the nuisance factor itself. A complete locational analysis supports a more credible damages conclusion.", "Teaching Point 3 — Market-Dependent in agricultural context. Factors B and C are Market-Dependent because buyer response in rural markets genuinely varies. Classifying rural character or private utilities as automatically Negative applies suburban standards to a rural market — a methodological error that opposing counsel will exploit under cross-examination."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "Documented odor complaints from a commercial hog operation 0.6 miles away represent a classic agricultural nuisance externality. Wind-dependent odor is a documented Negative — intermittent nature of the impact does not eliminate the classification, as buyers price the risk of adverse conditions."}, "B": {"present": true, "classification": "Market-Dependent", "rationale": "Rural agricultural character is expected in this market and accepted by many rural buyers as characteristic. However, buyers relocating from suburban areas may view it as a constraint. Market-Dependent reflects this genuine split in buyer response."}, "C": {"present": true, "classification": "Market-Dependent", "rationale": "In a rural market where private utilities are the norm, Market-Dependent is appropriate — primary residential buyers may resist while rural lifestyle buyers accept it as characteristic of the location."}, "D": {"present": true, "classification": "Negative", "rationale": "An 11-mile distance to the nearest grocery is a material service constraint for primary residential buyers — a documented Negative for buyers evaluating daily convenience in a non-resort rural market."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no flood insurance required."}, "F": {"present": true, "classification": "Negative", "rationale": "Limited extracurricular programming relative to Spartanburg County alternatives is a documented Negative for family buyers comparing rural and suburban school options."}, "G": {"present": false}, "H": {"present": false}}}'::jsonb
