  '',
  '{"subject": {"address_summary": "4112 Highway 290, Duncan, SC 29334", "subject_summary": "3BR/2BA · 1,540 SF · 2001-built SFR · Rural Spartanburg County · 0.9 acres", "context_label": "Litigation Context", "context_text": "Retained by insurance carrier. Fire loss occurred approximately 2 years ago. Effective date of value is the date of loss. Locational conditions must reflect what existed at that date — not current conditions. A municipal landfill operating 0.7 miles from the subject at the date of loss has since been closed and capped."}, "location_profile": ["The subject is a single-family residence on a 0.9-acre lot along Highway 290 in Duncan, Spartanburg County. As of the date of loss approximately 2 years ago, the area was characterized by rural residential and agricultural uses. Highway 290 provided access to I-85 approximately 3 miles west — a positive connectivity attribute for regional employment access at the date of loss.", "As of the date of loss, a Spartanburg County municipal landfill operated approximately 0.7 miles northwest of the subject. At that time, the landfill was in active operation with documented truck traffic on Highway 290 and periodic odor complaints recorded in county records. The landfill was closed and capped after the date of loss — that current condition is irrelevant to this assignment. The subject was served by private well and septic at the date of loss. The applicable school district was average-performing in a rural zone. FEMA Zone X has been confirmed both currently and at the date of loss."], "factors": [{"id": "A", "label": "Active municipal landfill proximity (0.7 miles — condition at date of loss)"}, {"id": "B", "label": "Highway 290 / I-85 regional access (3 miles)"}, {"id": "C", "label": "Average rural school district"}, {"id": "D", "label": "Private well and septic"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "Closed / remediated landfill (current condition — not present at effective date)"}, {"id": "G", "label": "HOA amenities"}, {"id": "H", "label": "Premium school district"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Retrospective analysis requires effective-date conditions. The most critical competency here is recognizing that Factor A (active landfill) describes the condition at the date of loss. The landfill closure is irrelevant. Students who classify the landfill as absent or note its current closure are analyzing current conditions at the wrong effective date — a fundamental methodological error in retrospective appraisal.", "Teaching Point 2 — Factor F is the key distractor. The closed/remediated landfill represents a current condition, not an effective-date condition. Students who check F are applying current knowledge to a retrospective assignment. The appraiser cannot benefit from hindsight when establishing value at a prior date. Every factor identification must be grounded in evidence available at or before the effective date.", "Teaching Point 3 — Effective-date evidence standard. Every factor identified in a retrospective assignment must be supported by evidence that existed at or before the effective date. Market data, county records, historical aerial photography, and period MLS records are appropriate sources. Current observations and current data are not. This discipline is what makes retrospective appraisals defensible in insurance and casualty loss litigation."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "As of the effective date, the landfill was in active operation with documented truck traffic and odor complaints. Active landfill proximity at 0.7 miles is a Negative that must be analyzed as it existed at the date of loss — not as it exists today."}, "B": {"present": true, "classification": "Positive", "rationale": "I-85 access within 3 miles via Highway 290 provided regional employment connectivity — a positive locational attribute that existed at the date of loss."}, "C": {"present": true, "classification": "Neutral", "rationale": "Average-performing rural zone with no documented buyer preference premium at the date of loss — Neutral classification is appropriate."}, "D": {"present": true, "classification": "Market-Dependent", "rationale": "In a rural market, private utilities are the norm. Market-Dependent reflects the genuine split in buyer acceptance — direction requires comparable sales evidence from the relevant period."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X was confirmed at the date of loss — the same condition as today. No flood insurance was required."}, "F": {"present": false}, "G": {"present": false}, "H": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C2'
  AND s.order_index = 6;

