-- Scenario 7: 2218 Lake Cunningham Road, Greer — 500kV Transmission Corridor Diminution (Defense)
-- Category M2-S5-C2 #7 · difficulty 'advanced'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 7,
  'advanced',
  '2218 Lake Cunningham Road, Greer — 500kV Transmission Corridor Diminution (Defense)',
  'You are retained as the appraisal expert in a litigation support engagement at 2218 Lake Cunningham Road, Greer, SC 29651. The subject is 3BR/2.5BA · 2,280 SF · 2003-built SFR · Lake Cunningham Estates. Retained by defense (utility company). Plaintiff claims installation of a 500kV transmission line corridor along the rear lot line 4 years ago caused measurable and ongoing diminution. Plaintiff''s expert claims a 12–15% value reduction; defendant disputes both the classification and the magnitude. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence, and write a brief market-supported rationale for each classification. The appraiser''s role in litigation is impartial classification: the retaining party does not change which factors are present or how they should be classified. Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence from the location profile and be defensible under cross-examination.'
FROM scenario_categories WHERE code = 'M2-S5-C2';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "2218 Lake Cunningham Road, Greer, SC 29651", "subject_summary": "3BR/2.5BA · 2,280 SF · 2003-built SFR · Lake Cunningham Estates", "context_label": "Litigation Context", "context_text": "Retained by defense (utility company). Plaintiff claims installation of a 500kV transmission line corridor along the rear lot line 4 years ago caused measurable and ongoing diminution. Plaintiff''s expert claims a 12–15% value reduction; defendant disputes both the classification and the magnitude."}, "location_profile": ["Lake Cunningham Estates is a residential subdivision of approximately 95 homes developed 2000–2006 near Lake Cunningham in northern Greenville County, approximately 6 miles north of downtown Greer. Lake Cunningham provides recreational access via a public boat landing 0.3 miles from the subject. The subdivision has no HOA. Lots range from 0.30 to 0.55 acres.", "2218 Lake Cunningham Road is a rear-facing lot whose rear property line runs along the edge of a Duke Energy 500kV transmission line corridor installed approximately 4 years ago. The corridor is approximately 100 feet wide with steel lattice towers at intervals. The towers and lines are visible from the rear yard and from second-floor windows. Prior to installation, the rear of the lot backed to wooded acreage — that natural buffer no longer exists along the transmission corridor. The subject is in the Greer/Eastside school attendance zone, above-average in Greenville County with documented positive buyer reception. FEMA Zone X is confirmed."], "factors": [{"id": "A", "label": "500kV transmission line corridor along rear lot line (installed 4 years ago)"}, {"id": "B", "label": "Lake Cunningham recreational proximity (0.3 miles, public access)"}, {"id": "C", "label": "Wooded rear view corridor (partially altered by transmission structures)"}, {"id": "D", "label": "Greer/Eastside school district (above average)"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "Semi-rural / lower density residential character"}, {"id": "G", "label": "HOA common area"}, {"id": "H", "label": "Industrial corridor adjacency"}, {"id": "I", "label": "Railroad proximity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Classification and magnitude are separate analytical questions. Factor A (transmission line) is Negative — the appraiser''s job is to identify and classify it accurately regardless of which party retained them. The litigation dispute is about magnitude, not classification. Students who classify it as Market-Dependent to soften the impact for the defense are making an advocacy error. Defense experts dispute how much, not whether.", "Teaching Point 2 — Before-condition is part of the analysis. The prior wooded buffer (Factor C) is a distinct consideration from the transmission line itself (Factor A): C addresses the loss of privacy and natural views, while A addresses proximity, visual presence, and potential electromagnetic concerns. Both must be identified independently — they address different dimensions of the same installation.", "Teaching Point 3 — Positive factors establish the before-condition context. Factors B, D, and E are positive locational influences that the defense appraiser should identify accurately — they establish the overall positive locational context in which the transmission line impact must be quantified. Omitting positive factors to minimize the before-value would undermine the appraiser''s credibility as a neutral analyst."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "A 500kV transmission corridor on the rear lot line — with towers visible from the property and elimination of the prior wooded buffer — is a documented Negative. Magnitude is the litigation dispute; the Negative classification is not. Appraisers retained by either party must classify this factor accurately."}, "B": {"present": true, "classification": "Positive", "rationale": "Public lake access within 0.3 miles is a documented positive amenity in this submarket for buyers who prioritize recreational water access."}, "C": {"present": true, "classification": "Market-Dependent", "rationale": "The wooded rear buffer that provided privacy and natural views prior to tower installation has been structurally altered. The residual view value depends on buyer perception of remaining natural character vs. transmission infrastructure — Market-Dependent is appropriate as buyer response varies."}, "D": {"present": true, "classification": "Positive", "rationale": "Above-average rating with documented positive buyer reception — a market-supported Positive in this submarket."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed."}, "F": {"present": true, "classification": "Market-Dependent", "rationale": "Lower-density, semi-rural character appeals to buyers seeking privacy and land; others prefer more amenity-rich suburban settings. Market-Dependent reflects this genuine split in buyer preference."}, "G": {"present": false}, "H": {"present": false}, "I": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C2'
  AND s.order_index = 7;

