-- Scenario 8: 847 Buncombe Road, Greenville — Pre-Existing Auto Salvage Yard Diminution
-- Category M2-S5-C2 #8 · difficulty 'advanced'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 8,
  'advanced',
  '847 Buncombe Road, Greenville — Pre-Existing Auto Salvage Yard Diminution',
  'You are retained as the appraisal expert in a litigation support engagement at 847 Buncombe Road, Greenville, SC 29609. The subject is 3BR/2BA · 1,540 SF · 1992-built SFR (renovated 2015) · Buncombe Road Corridor. Retained by plaintiff''s attorney. Claim: a long-operating auto salvage yard on the immediately adjacent parcel has caused ongoing diminution. Defendant argues the salvage yard predated the plaintiff''s purchase and any impact was already reflected in the purchase price. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence, and write a brief market-supported rationale for each classification. The appraiser''s role in litigation is impartial classification: the retaining party does not change which factors are present or how they should be classified. Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence from the location profile and be defensible under cross-examination.'
FROM scenario_categories WHERE code = 'M2-S5-C2';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "847 Buncombe Road, Greenville, SC 29609", "subject_summary": "3BR/2BA · 1,540 SF · 1992-built SFR (renovated 2015) · Buncombe Road Corridor", "context_label": "Litigation Context", "context_text": "Retained by plaintiff''s attorney. Claim: a long-operating auto salvage yard on the immediately adjacent parcel has caused ongoing diminution. Defendant argues the salvage yard predated the plaintiff''s purchase and any impact was already reflected in the purchase price."}, "location_profile": ["The subject is a renovated single-family residence in the Buncombe Road corridor of Greenville, approximately 1.5 miles southwest of downtown. The corridor is characterized by older residential properties, auto-oriented commercial businesses, and light industrial uses. Some residential renovation investment has occurred since 2015, but land use remains mixed and the commercial character of Buncombe Road is pronounced.", "847 Buncombe Road is on a 0.12-acre lot with direct Buncombe Road frontage and a 28-foot setback from the road edge. The immediately adjacent parcel to the north is occupied by an auto salvage yard that has operated at this location for over 30 years — predating the subject''s residential construction. The salvage yard generates visual blight from stacked vehicles, periodic noise from vehicle processing, and customer traffic during operating hours. The subject is in a below-average school attendance zone. Downtown Greenville employment and amenities are approximately 1.5 miles east via Buncombe Road. FEMA Zone X is confirmed. No HOA exists."], "factors": [{"id": "A", "label": "Auto salvage yard immediately adjacent (north parcel)"}, {"id": "B", "label": "Buncombe Road commercial/arterial frontage (28-ft setback)"}, {"id": "C", "label": "Downtown Greenville employment and amenity proximity (1.5 miles)"}, {"id": "D", "label": "Below-average school district for this corridor"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "Mixed residential/commercial/industrial corridor character"}, {"id": "G", "label": "HOA restrictions or amenity"}, {"id": "H", "label": "Premium school district"}, {"id": "I", "label": "Lake or water amenity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Pre-existing condition defense does not change the classification. The defendant argues the salvage yard predated the purchase and was already reflected in the price. This is a legal argument, not a locational one. The appraiser''s job is to identify and classify Factor A as Negative regardless of when it was established. Whether the impact was already priced in at purchase is an analytical question about the comparable pool, not a reason to reclassify the factor.", "Teaching Point 2 — Multiple negatives compound. This scenario has three Negative factors (A, B, D) and one Market-Dependent (F). Students who identify only the salvage yard are missing the full locational picture that opposing counsel will address. In litigation, the completeness of the locational analysis is as important as the accuracy of any single classification.", "Teaching Point 3 — Corridor character as a distinct factor. Factor F (mixed-use character) is analytically distinct from both the arterial noise (B) and the salvage yard (A). Factor F addresses the broader land use context defining the market area and affecting comparable selection. Students who collapse all three into a single analysis are losing the precision that litigation testimony requires."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "A 30+ year auto salvage operation directly adjacent — with visual blight from stacked vehicles, ongoing noise, and customer traffic — is a textbook proximity externality. Negative classification is straightforward; magnitude is the litigation question."}, "B": {"present": true, "classification": "Negative", "rationale": "Direct frontage on a commercial arterial with a 28-foot setback introduces noise, traffic, and commercial character concerns — a consistently Negative residential locational factor at this proximity."}, "C": {"present": true, "classification": "Positive", "rationale": "Downtown Greenville employment and amenities within 1.5 miles are a documented positive in this submarket for buyers who prioritize urban proximity and walkable access."}, "D": {"present": true, "classification": "Negative", "rationale": "The below-average school zone is a documented Negative for family buyers — particularly relevant where school district is a frequent buyer search filter."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no flood insurance requirement."}, "F": {"present": true, "classification": "Market-Dependent", "rationale": "The corridor''s mixed-use character creates the urban proximity positive (C) but also contributes to commercial and industrial concerns. Buyer response to living in this environment is genuinely split — some seek it; others exclude it. This factor is analytically distinct from A and B."}, "G": {"present": false}, "H": {"present": false}, "I": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C2'
  AND s.order_index = 8;

