  'expert',
  '1234 Poinsett Highway, Greenville — Retrospective Misrepresentation Suit',
  'You are retained as the appraisal expert in a litigation support engagement at 1234 Poinsett Highway, Greenville, SC 29609. The subject is 3BR/1.5BA · 1,340 SF · 1962-built SFR (updated 2018) · Poinsett Highway Corridor. Retained by defense in a misrepresentation lawsuit. Plaintiff purchased 5 years ago and claims conditions were materially different from what was represented. Appraiser must establish what locational conditions actually existed at the date of purchase using documented historical evidence — not current conditions. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence, and write a brief market-supported rationale for each classification. The appraiser''s role in litigation is impartial classification: the retaining party does not change which factors are present or how they should be classified. Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence from the location profile and be defensible under cross-examination.'
FROM scenario_categories WHERE code = 'M2-S5-C2';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "1234 Poinsett Highway, Greenville, SC 29609", "subject_summary": "3BR/1.5BA · 1,340 SF · 1962-built SFR (updated 2018) · Poinsett Highway Corridor", "context_label": "Litigation Context", "context_text": "Retained by defense in a misrepresentation lawsuit. Plaintiff purchased 5 years ago and claims conditions were materially different from what was represented. Appraiser must establish what locational conditions actually existed at the date of purchase using documented historical evidence — not current conditions."}, "location_profile": ["The subject is located on Poinsett Highway in northern Greenville, approximately 3 miles from downtown. Poinsett Highway is a state-maintained arterial with a commercial and industrial corridor mix that has been in transition over the past decade. As of the date of purchase 5 years ago, the immediate area included active light industrial tenants, older commercial buildings with variable occupancy, and scattered residential properties — a genuinely mixed-use environment with no clear residential character at that time.", "As of 5 years ago, the subject fronted directly on Poinsett Highway with a 20-foot setback. MLS records from that period document high price variance within short distances along the corridor — a condition reflecting market instability. The below-average school attendance zone applicable at the date of purchase is the same zone that applies today. The downtown Greenville proximity (3 miles) was a feature of the location then as now, though the downtown amenity corridor was substantially less developed at the date of purchase than it is today. FEMA Zone X has been confirmed both currently and at the date of purchase."], "factors": [{"id": "A", "label": "Industrial/mixed-use land use pattern (condition at date of purchase)"}, {"id": "B", "label": "Poinsett Highway arterial frontage (20-ft setback)"}, {"id": "C", "label": "Downtown Greenville proximity (3 miles — effective-date buyer response)"}, {"id": "D", "label": "Below-average school district (condition at date of purchase)"}, {"id": "E", "label": "FEMA Zone X"}, {"id": "F", "label": "Residential price volatility (condition at date of purchase)"}, {"id": "G", "label": "Neighborhood in transition (condition at date of purchase)"}, {"id": "H", "label": "Current downtown amenity premium (current condition — not present at effective date)"}, {"id": "I", "label": "Premium school district"}, {"id": "J", "label": "HOA amenity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — The effective date governs every factor. Each factor must reflect conditions as of the date of purchase, 5 years ago. The current positive amenity value of the downtown corridor (Factor H distractor) is not present at the effective date — it developed after purchase. Students who check H are applying current knowledge to a retrospective assignment. Every identified factor must be supportable with evidence that existed at the effective date.", "Teaching Point 2 — Market-Dependent at the effective date vs. today. Factor C (downtown proximity) is Market-Dependent at the date of purchase because the amenity corridor was less developed and buyer response was split. Today it might be classified Positive — but the question is what market evidence showed 5 years ago, not now. Students who classify current conditions instead of effective-date conditions are making the fundamental error in retrospective appraisal.", "Teaching Point 3 — Transitional language discipline applies to retrospective assignments equally. Factor G (neighborhood in transition) must be classified using objective, market-supported evidence from the effective-date period — permit records, MLS data, price trend analysis. Demographic language about who was moving into or out of the neighborhood is impermissible regardless of the effective date. Fair Housing compliance applies to historical assignments the same as current ones."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Negative", "rationale": "At the date of purchase, the corridor''s active light industrial and commercial tenancy with variable occupancy was a documented Negative for residential buyers seeking stable neighborhood context — supported by MLS and permit records from the relevant period."}, "B": {"present": true, "classification": "Negative", "rationale": "Direct frontage on a state arterial at 20 feet is consistently Negative for residential use — this condition existed at the date of purchase and exists today."}, "C": {"present": true, "classification": "Market-Dependent", "rationale": "At the date of purchase, downtown Greenville was less developed as a residential amenity corridor. Buyer response to this corridor''s then-current amenity level was split — Market-Dependent is appropriate for the effective date. Classifying this as Positive would apply current conditions to a historical assignment."}, "D": {"present": true, "classification": "Negative", "rationale": "The same below-average school zone applicable today was applicable at the date of purchase — a Negative documented in market data from the relevant period."}, "E": {"present": true, "classification": "Positive", "rationale": "Zone X at the date of purchase — confirmed by FEMA maps applicable at that time. Positive."}, "F": {"present": true, "classification": "Negative", "rationale": "MLS records from the period document high price variance within the corridor — a Negative locational indicator reflecting market instability that risk-averse buyers and lenders discounted at the time of purchase."}, "G": {"present": true, "classification": "Market-Dependent", "rationale": "The corridor showed observable land use change at the date of purchase — some buyers viewed this as an opportunity; others required stability. Market-Dependent is appropriate and all supporting language must reference objective market evidence, not demographic characteristics of residents."}, "H": {"present": false}, "I": {"present": false}, "J": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C2'
  AND s.order_index = 9;

