-- Scenario 10: 3318 Pelham Road, Greenville — Court-Appointed Neutral, Neighborhood Boundary Dispute
-- Category M2-S5-C2 #10 · difficulty 'expert'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 10,
  'expert',
  '3318 Pelham Road, Greenville — Court-Appointed Neutral, Neighborhood Boundary Dispute',
  'You are retained as the appraisal expert in a litigation support engagement at 3318 Pelham Road, Greenville, SC 29615. The subject is 4BR/2.5BA · 2,440 SF · 2001-built SFR · Pelham Road Residential. Court-appointed neutral expert in a real estate contract dispute. Buyer and seller each have appraisers with fundamentally different neighborhood boundary definitions producing materially different value conclusions. The court requires an independent locational analysis to support a defensible neighborhood determination. Section 5 — Locational Influence — requires you to identify which locational factors are present at the subject, classify each as Positive, Negative, Neutral, or Market-Dependent based on the location profile evidence, and write a brief market-supported rationale for each classification. The appraiser''s role in litigation is impartial classification: the retaining party does not change which factors are present or how they should be classified. Distractor factors that are not present must be left unchecked, and each rationale must cite specific evidence from the location profile and be defensible under cross-examination.'
FROM scenario_categories WHERE code = 'M2-S5-C2';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject": {"address_summary": "3318 Pelham Road, Greenville, SC 29615", "subject_summary": "4BR/2.5BA · 2,440 SF · 2001-built SFR · Pelham Road Residential", "context_label": "Litigation Context", "context_text": "Court-appointed neutral expert in a real estate contract dispute. Buyer and seller each have appraisers with fundamentally different neighborhood boundary definitions producing materially different value conclusions. The court requires an independent locational analysis to support a defensible neighborhood determination."}, "location_profile": ["The subject is a single-family residence on Pelham Road in northeastern Greenville County, approximately 0.3 miles from Pelham Forest — an upscale subdivision with home values averaging 30–40% above the subject''s immediate neighborhood. The subject''s immediate neighborhood consists of conventional middle-market homes built primarily 1998–2008 on lots of 0.18–0.30 acres. The plaintiff''s appraiser drew the neighborhood boundary to include Pelham Forest, producing comparables with significantly higher sale prices. The defendant''s appraiser excluded Pelham Forest and drew the boundary to the subject''s immediate subdivision.", "3318 Pelham Road is a through-lot — not a cul-de-sac — on a moderate-traffic residential street. A commercial office park occupies the adjacent parcel to the east; the office use is low-intensity with no observable noise, odor, or traffic impact on the subject. I-385 access is approximately 0.4 miles south via Pelham Road, providing strong regional connectivity. The subject is in the Eastside school attendance zone, above-average in Greenville County. FEMA Zone X is confirmed. The immediate neighborhood shows moderate variation in housing stock age and condition with some deferred maintenance observable on older units. No HOA exists on the subject''s block, though Pelham Forest carries an active HOA."], "factors": [{"id": "A", "label": "Proximity to Pelham Forest upscale subdivision (0.3 miles)"}, {"id": "B", "label": "I-385 regional highway access (0.4 miles)"}, {"id": "C", "label": "Eastside school district (above average)"}, {"id": "D", "label": "FEMA Zone X"}, {"id": "E", "label": "Through-street location (moderate traffic)"}, {"id": "F", "label": "Adjacent commercial office park (low-intensity, no direct impact)"}, {"id": "G", "label": "Mixed housing stock age and condition in immediate neighborhood"}, {"id": "H", "label": "Cul-de-sac location"}, {"id": "I", "label": "HOA common area backing"}, {"id": "J", "label": "Railroad proximity"}], "classification_options": ["Positive", "Negative", "Neutral", "Market-Dependent"], "min_rationale_chars": 20, "teaching_points": ["Teaching Point 1 — Neighborhood boundary is a locational analysis conclusion, not a starting point. The court-appointed expert must identify and classify the locational factors present at the subject and let those factors inform the neighborhood boundary — not the reverse. Students who decide which comparables they want to use and then identify factors to support that decision are performing advocacy, not analysis. The factors drive the boundary; the boundary does not drive the factors.", "Teaching Point 2 — Proximity to a higher-value neighborhood is Market-Dependent, not Positive. Factor A requires careful classification. The subject is near Pelham Forest but is not part of it. Proximity may provide some associational benefit, but does not mean the subject competes in the same market segment. Market-Dependent is the honest answer — direction depends on whether a measurable halo effect is supported by paired sales evidence, not on the appraiser''s neighborhood boundary preference.", "Teaching Point 3 — Neutral classifications require as much support as directional ones. Factor F (adjacent office park) is Neutral because the profile provides specific evidence: low intensity, no observable impact. In litigation, a Neutral classification unsupported by specific observation and market evidence is as vulnerable under cross-examination as an unsupported Positive or Negative. ''It does not appear to affect anything'' is not a defensible rationale — the appraiser must articulate what they observed and what the market evidence shows."]}'::jsonb,
  '{"factors": {"A": {"present": true, "classification": "Market-Dependent", "rationale": "Proximity to a higher-value neighborhood may provide an amenity association benefit for some buyers, but does not make the subject comparable to Pelham Forest properties. Market-Dependent is appropriate — the direction depends on whether proximity provides a measurable halo effect in this specific submarket, which requires paired sales evidence to establish."}, "B": {"present": true, "classification": "Positive", "rationale": "I-385 access within 0.4 miles via Pelham Road provides strong regional connectivity — a documented positive in a submarket where commute access is a buyer priority."}, "C": {"present": true, "classification": "Positive", "rationale": "Above-average district rating with documented positive buyer reception — a market-supported Positive shared by the subject and most properties in the immediate neighborhood."}, "D": {"present": true, "classification": "Positive", "rationale": "Zone X confirmed — no flood insurance requirement."}, "E": {"present": true, "classification": "Negative", "rationale": "The subject is on a through-street with moderate traffic — a modest Negative relative to cul-de-sac configurations, though less pronounced than on high-volume arterials."}, "F": {"present": true, "classification": "Neutral", "rationale": "The adjacent office park generates minimal noise, no odor, and no measurable traffic impact on the subject. At this level of intensity, Neutral is the correct classification — the commercial use is present but produces no detectable buyer price response in this context."}, "G": {"present": true, "classification": "Market-Dependent", "rationale": "The immediate neighborhood shows variation in housing age and maintenance — some buyers discount this as a stability concern; others view it as a value opportunity. Market-Dependent reflects this genuine split and is relevant to the neighborhood boundary determination."}, "H": {"present": false}, "I": {"present": false}, "J": {"present": false}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'factor_analysis'
WHERE sc.code = 'M2-S5-C2'
  AND s.order_index = 10;

COMMIT;
